manipulate.code:
# Get all alive players in initiative_order players = data.initiative_order.select { |ent| ent["type"] == "player" }
if players.empty? data.continue_game = false data.reason = 1 return else all_at_end = players.all? do |pl| conds = pl["conditions"].map(&:to_s) conds.include?("reached_end") end
if all_at_end data.continue_game = false data.reason = 2 return end end
